   165→## 源码解析
   166→
   167→### Canvas.UpdateCanvasBatch
   168→
   169→Unity 2021.3 核心代码（简化版）：
   170→
   171→```csharp
   172→// Canvas.cs
   173→private void UpdateCanvasBatch()
   174→{
   175→    // 1. 收集所有可批次的Graphic
   176→    var graphicList = ListPool<Graphic>.Get();
   177→
   178→    for (int i = 0; i < transform.childCount; i++)
   179→    {
   180→        var graphic = transform.GetChild(i).GetComponent<Graphic>();
   181→        if (graphic != null && graphic.canvasRenderer.hasPopInstruction == false)
   182→        {
   183→            graphicList.Add(graphic);
   184→        }
   185→    }
   186→
   187→    // 2. 按材质和纹理排序
   188→    graphicList.Sort((a, b) =>
   189→    {
   190→        // 优先按Material排序
   191→        int materialCompare = CompareMaterial(a.material, b.material);
   192→        if (materialCompare != 0)
   193→            return materialCompare;
   194→
   195→        // 其次按Texture排序
   196→        int textureCompare = CompareTexture(a.mainTexture, b.mainTexture);
   197→        return textureCompare;
   198→    });
   199→
   200→    // 3. 合批构建
   201→    Material currentMaterial = null;
   202→    Texture currentTexture = null;
   203→
   204→    foreach (var graphic in graphicList)
   205→    {
   206→        // 如果材质或纹理改变，开始新批次
   207→        if (currentMaterial != graphic.material ||
   208→            currentTexture != graphic.mainTexture)
   209→        {
   210→            // 结束当前批次
   211→            FlushBatch();
   212→
   213→            // 开始新批次
   214→            currentMaterial = graphic.material;
   215→            currentTexture = graphic.mainTexture;
   216→            BeginBatch(currentMaterial, currentTexture);
   217→        }
   218→
   219→        // 添加到当前批次
   220→        AddToBatch(graphic);
   221→    }
   222→
   223→    // 4. 提交最后批次
   224→    FlushBatch();
   225→
   226→    ListPool<Graphic>.Release(graphicList);
   227→}
   228→```
