   261→### CanvasUpdateRegistry
   262→
   263→```csharp
   264→// CanvasUpdateRegistry.cs
   265→public static class CanvasUpdateRegistry
   266→{
   267→    private static readonly List<ICanvasElement> s_LayoutRebuildQueue = new();
   268→    private static readonly List<ICanvasElement> s_GraphicRebuildQueue = new();
   269→
   270→    public static void RegisterCanvasElementForLayoutRebuild(ICanvasElement element)
   271→    {
   272→        if (!s_LayoutRebuildQueue.Contains(element))
   273→        {
   274→            s_LayoutRebuildQueue.Add(element);
   275→        }
   276→    }
   277→
   278→    public static void RegisterCanvasElementForGraphicRebuild(ICanvasElement element)
   279→    {
   280→        if (!s_GraphicRebuildQueue.Contains(element))
   281→        {
   282→            s_GraphicRebuildQueue.Add(element);
   283→        }
   284→    }
   285→
   286→    public static void FullLayoutUpdate()
   287→    {
   288→        // 按顺序执行布局重建
   289→        for (int i = 0; i < s_LayoutRebuildQueue.Count; i++)
   290→        {
   291→            s_LayoutRebuildQueue[i].Rebuild(CanvasUpdate.Layout);
   292→        }
   293→        s_LayoutRebuildQueue.Clear();
   294→    }
   295→
   296→    public static void FullGraphicUpdate()
   297→    {
   298→        // 按顺序执行图形重建
   299→        for (int i = 0; i < s_GraphicRebuildQueue.Count; i++)
   300→        {
   301→            s_GraphicRebuildQueue[i].Rebuild(CanvasUpdate.PreRender);
   302→        }
   303→        s_GraphicRebuildQueue.Clear();
   304→    }
   305→}
   306→```
