   444→## 实战案例
   445→
   446→### 案例1: 滚动列表优化
   447→
   448→**问题：** 100个Item的ScrollList，滚动时帧率掉到30FPS
   449→
   450→**诊断：**
   451→```
   452→1. 每个Item独立Canvas → DrawCall爆炸（100+）
   453→2. Text每帧Graphic Rebuild → CPU瓶颈
   454→3. 非可视区域也在渲染 → 浪费GPU
   455→```
   456→
   457→**解决方案：**
   458→
   459→```csharp
   460→// 1. 使用ObjectPool
   461→public class ScrollListPool : MonoBehaviour
   462→{
   463→    [SerializeField] private GameObject itemPrefab;
   464→    [SerializeField] private RectTransform content;
   465→    [SerializeField] private int poolSize = 20;
   466→
   467→    private ObjectPool<GameObject> pool;
   468→    private List<GameObject> activeItems = new();
   469→
   470→    private void Awake()
   471→    {
   472→        pool = new ObjectPool<GameObject>(
   473→            createFunc: () => Instantiate(itemPrefab, content),
   474→            actionOnGet: (item) => item.SetActive(true),
   475→            actionOnRelease: (item) => item.SetActive(false),
   476→            maxSize: poolSize
   477→        );
   478→    }
   479→
   480→    public void SetItems(List<ItemData> items)
   481→    {
   482→        // 清空当前显示
   483→        foreach (var item in activeItems)
   484→        {
   485→            pool.Release(item);
   486→        }
   487→        activeItems.Clear();
   488→
   489→        // 创建新Item
   490→        foreach (var data in items)
   491→        {
   492→            var item = pool.Get();
   493→            item.GetComponent<ItemView>().SetData(data);
   494→            activeItems.Add(item);
   495→        }
   496→    }
   497→}
   498→
   499→// 2. 可视区域剔除
   500→public class ScrollListCulling : MonoBehaviour
   501→{
   502→    [SerializeField] private RectTransform viewport;
   503→    [SerializeField] private RectTransform content;
   504→
   505→    private void Update()
   506→    {
   507→        float viewportTop = viewport.rect.height / 2;
   508→        float viewportBottom = -viewport.rect.height / 2;
   509→
   510→        foreach (Transform child in content)
   511→        {
   512→            var itemRect = (RectTransform)child;
   513→            Vector2 localPos = content.InverseTransformPoint(itemRect.position);
   514→
   515→            // 只渲染可视区域的Item
   516→            itemRect.gameObject.SetActive(
   517→                localPos.y < viewportTop && localPos.y > viewportBottom
   518→            );
   519→        }
   520→    }
   521→}
   522→
   523→// 3. 减少Text Rebuild
   524→public class OptimizedText : MonoBehaviour
   525→{
   526→    private TextMeshProUGUI textComponent;
   527→    private string lastText;
   528→
   529→    private void Awake()
   530→    {
   531→        textComponent = GetComponent<TextMeshProUGUI>();
   532→    }
   533→
   534→    public void SetText(string newText)
   535→    {
   536→        // 只在内容改变时更新
   537→        if (newText != lastText)
   538→        {
   539→            textComponent.text = newText;
   540→            lastText = newText;
   541→
   542→            // 强制立即重建，避免异步重建
   543→            textComponent.ForceMeshUpdate();
   544→        }
   545→    }
   546→}
   547→```
   548→
   549→**优化效果：**
   550→- DrawCall: 100+ → 5
   551→- Frame Time: 33ms → 8ms
   552→- FPS: 30 → 120+
