   759→
   760→// 方案2：减少更新频率
   761→private float lastUpdateTime;
   762→
   763→void Update()
   764→{
   765→    if (Time.time - lastUpdateTime > 0.1f)  // 10Hz更新
   766→    {
   767→        text.text = $"Score: {score}";
   768→        lastUpdateTime = Time.time;
   769→    }
   770→}
   771→
   772→// 方案3：使用ObjectPool + 复用Text
   773→public class TextPool : MonoBehaviour
   774→{
   775→    private Queue<TextMeshProUGUI> pool = new();
   776→
   777→    public TextMeshProUGUI GetText()
   778→    {
   779→        if (pool.Count > 0)
   780→        {
   781→            return pool.Dequeue();
   782→        }
   783→        return Instantiate(prefab);
   784→    }
   785→
   786→    public void ReturnText(TextMeshProUGUI text)
   787→    {
   788→        text.SetText("");  // 清空但保持对象活跃
   789→        pool.Enqueue(text);
   790→    }
   791→}
   792→```
   793→
   794→### 坑3: Canvas Scaler导致的性能问题
   795→
   796→**现象：** UI元素位置计算异常、DrawCall增加
   797→
   798→**根因：**
   799→```
   800→Canvas Scaler: Scale With Screen Size
   801→├─> 每帧计算缩放比例
   802→├─> 所有RectTransform重新计算
   803→└─> Layout System重新布局
   804→```
   805→
   806→**解决方案：**
   807→```csharp
   808→// 固定分辨率缩放
   809→public class FixedResolutionScaler : MonoBehaviour
   810→{
   811→    private const int ReferenceWidth = 1920;
   812→    private const int ReferenceHeight = 1080;
   813→
   814→    private CanvasScaler scaler;
   815→
   816→    private void Awake()
   817→    {
   818→        scaler = GetComponent<CanvasScaler>();
   819→        scaler.uiScaleMode = CanvasScaler.ScaleMode.ConstantPixelSize;
   820→        scaler.scaleFactor = GetScaleFactor();
   821→    }
   822→
   823→    private float GetScaleFactor()
   824→    {
   825→        float referenceRatio = (float)ReferenceWidth / ReferenceHeight;
   826→        float screenRatio = (float)Screen.width / Screen.height;
   827→
   828→        if (screenRatio > referenceRatio)
   829→        {
   830→            // 宽屏，基于高度缩放
   831→            return (float)Screen.height / ReferenceHeight;
   832→        }
   833→        else
   834→        {
   835→            // 窄屏，基于宽度缩放
   836→            return (float)Screen.width / ReferenceWidth;
   837→        }
   838→    }
   839→}
   840→```
   841→
   842→### 坑4: 多Canvas的Sorting Layer切换开销
   843→
   844→**现象：** 动态修改Canvas sortingOrder导致卡顿
   845→
   846→**根因：** Sorting Order改变会触发整个渲染队列重组
   847→
   848→**解决方案：**
   849→```csharp
   850→// 错误做法
   851→canvas.sortingOrder = ++counter;
   852→
   853→// 正确做法：使用父子层级控制深度
   854→public class DepthManager : MonoBehaviour
   855→{
   856→    private Transform[] depthLayers;
   857→
   858→    public void SetDepth(Transform uiObject, int depth)
   859→    {
   860→        // 通过父子关系控制深度，避免修改sortingOrder
   861→        if (depth >= 0 && depth < depthLayers.Length)
   862→        {
   863→            uiObject.SetParent(depthLayers[depth], false);
   864→        }
   865→    }
   866→
   867→    private void InitializeDepthLayers()
   868→    {
   869→        depthLayers = new Transform[10];
   870→        for (int i = 0; i < depthLayers.Length; i++)
   871→        {
   872→            var layer = new GameObject($"Depth_{i}").transform;
   873→            layer.SetParent(transform, false);
   874→            depthLayers[i] = layer;
   875→        }
   876→    }
   877→}
   878→```
